insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:5-2-sources-of-finance:misc:0f32266c', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> An overdraft is a good way to fund a major long-term investment like buying a building.</p><p><strong>✅ The correct idea:</strong> An overdraft is a short-term source designed for day-to-day cash flow problems. It is expensive (high daily interest) and not suitable for long-term investments. A bank loan or share issue would be more appropriate.</p>", "question": "Why is an overdraft not suitable for funding a major long-term investment?", "options": ["It requires the business to sell part of its ownership to a bank", "It is only available to businesses that have already made a large profit", "It is a short-term, expensive source designed for day-to-day cash flow gaps", "It cannot legally be arranged unless the business has zero debt"]}'::jsonb, '{"answer": 2, "explain": "The card explains an overdraft is short-term and expensive (high daily interest), designed for day-to-day cash flow problems rather than major long-term investments like buying a building."}'::jsonb),
('business:5-2-sources-of-finance:misc:06fee2a2', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Interest is only a disadvantage of bank loans.</p><p><strong>✅ The correct idea:</strong> Interest applies to overdrafts and trade credit (if not paid on time) as well as loans. Crowdfunding loans also carry interest. The only sources with no interest are internal sources (owner''s capital, retained profit) and share issues.</p>", "question": "Which sources of finance can also involve paying interest, besides bank loans?", "options": ["Sale of assets and retained profit are the only other examples", "Share issues and taking on a new partner are the only other examples", "Owner''s capital and retained profit are the only other examples", "Overdrafts and late trade credit, as well as crowdfunding loans"]}'::jsonb, '{"answer": 3, "explain": "The card corrects the idea that interest only applies to bank loans — overdrafts, late trade credit payments, and crowdfunding loans can all involve interest too."}'::jsonb),
('business:5-2-sources-of-finance:misc:7774e662', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Taking on a new partner means hiring a new employee who earns a salary.</p><p><strong>✅ The correct idea:</strong> A new partner is a co-owner of the business, not an employee. They contribute capital, share in the profits AND losses, and have the right to take part in decision-making. They do not earn a fixed salary.</p>", "question": "What is the correct status of a new partner joining a business?", "options": ["A lender who is repaid with interest over a fixed period of time", "A co-owner who contributes capital and shares in profits and losses", "An employee who is paid a fixed salary for the work they do", "A shareholder who receives a dividend but has no voting rights"]}'::jsonb, '{"answer": 1, "explain": "The card explains a new partner is a co-owner, not an employee — they contribute capital, share in profits AND losses, and take part in decision-making rather than earning a salary."}'::jsonb),
('business:5-2-sources-of-finance:misc:663fc108', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Using your own savings to finance a business is completely free with no cost at all.</p><p><strong>✅ The correct idea:</strong> Owner''s capital has no interest cost, but it does have an opportunity cost — the money could have been earning interest in a bank account or invested elsewhere. There is also the risk of losing personal savings if the business fails.</p>", "question": "What cost does using owner''s savings to finance a business actually involve?", "options": ["A fee paid to shareholders for the use of their personal savings", "No cost of any kind at all, since savings are always entirely free to use", "Interest charged by the bank on the amount of savings used", "An opportunity cost, since the money could have earned interest elsewhere"]}'::jsonb, '{"answer": 3, "explain": "The card explains owner''s capital has no interest cost but does have an opportunity cost, since the money could have earned interest elsewhere or been invested another way."}'::jsonb),
('business:5-2-sources-of-finance:misc:682a7325', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> For a ''recommend'' question, you only need to give reasons FOR your chosen option to get full marks.</p><p><strong>✅ The correct idea:</strong> OCR examiners require a comparative answer — you must explain why your chosen option is BETTER THAN the alternative. Answers that only discuss the chosen option without referencing the rejected option cannot score more than 1 mark for justification.</p>", "question": "What must a full-mark answer to a ''recommend'' question include?", "options": ["A general definition of finance with no reference to either option", "A complete list of every possible source of finance available", "Only reasons for the chosen option, without ever mentioning the alternative", "A comparison explaining why the chosen option is better than the alternative"]}'::jsonb, '{"answer": 3, "explain": "The card explains OCR requires a comparative answer justifying why the chosen option is better than the rejected one — answers covering only the chosen option score at most 1 mark."}'::jsonb),
('business:5-2-sources-of-finance:misc:43174c78', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A share issue means the business has to repay shareholders like a loan.</p><p><strong>✅ The correct idea:</strong> Money raised through a share issue does not need to be repaid. Shareholders own part of the business and may receive dividends if profits are made and distributed, but the original sum invested is not returned to them.</p>", "question": "Does money raised through a share issue need to be repaid like a loan?", "options": ["Yes — but only if the business fails to make a profit that year", "Yes — shareholders must be repaid the full amount plus additional interest", "No — but only if the shareholders agree in writing to waive repayment", "No — shareholders own part of the business and are not repaid the original sum"]}'::jsonb, '{"answer": 3, "explain": "The card corrects the misconception that a share issue must be repaid — shareholders own part of the business and may receive dividends, but the original investment is not repaid to them."}'::jsonb),
('business:5-2-sources-of-finance:misc:6f6832f3', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Crowdfunding always means people are donating money with nothing in return.</p><p><strong>✅ The correct idea:</strong> Crowdfunding can work in three ways: donors give money (common for community projects), lenders provide a loan (repaid with interest), or investors buy equity (a share of the business). Most business crowdfunding involves equity or lending.</p>", "question": "What does the card say about how crowdfunding contributions actually work?", "options": ["Contributors always receive a fixed rate of interest on their money", "Contributors may donate, lend, or buy equity — not just donate with nothing back", "Contributors always donate money with absolutely nothing given back in return", "Contributors always become full legal business partners as a result"]}'::jsonb, '{"answer": 1, "explain": "The card explains crowdfunding can work three ways — donation, loan, or equity — correcting the idea that it always means donations with nothing given in return."}'::jsonb),
('business:5-2-sources-of-finance:misc:733842c9', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> A bank loan and an overdraft are essentially the same thing.</p><p><strong>✅ The correct idea:</strong> They are very different. A bank loan is a fixed sum borrowed for a fixed period with set instalments. An overdraft is a flexible, daily arrangement where interest is charged only on the amount overdrawn — it varies day by day and is meant for short-term needs.</p>", "question": "What is the key difference between a bank loan and an overdraft?", "options": ["A loan is a fixed sum for a fixed period, while an overdraft is a flexible daily arrangement", "A loan requires no interest to be paid at all, while an overdraft always charges some interest", "A loan and an overdraft are essentially identical arrangements with a bank", "A loan is repaid daily, while an overdraft is repaid in one single lump sum"]}'::jsonb, '{"answer": 0, "explain": "The card explains a bank loan is a fixed sum for a fixed period with set instalments, while an overdraft is a flexible daily arrangement charged only on the amount overdrawn."}'::jsonb),
('business:5-2-sources-of-finance:tips:4182efcb', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1 mark — One Point. Full Stop. Move On.", "reading": "\n      <p>A 1-mark <strong>''Identify'' or ''State''</strong> question needs exactly one correct, specific point. No explanation. No examples. No paragraphs.</p>\n      <p><strong>Common question types:</strong></p>\n      <ul>\n        <li>\"Identify one reason, other than expansion, why a business needs finance.\" [1 mark]</li>\n        <li>\"State one disadvantage of using an overdraft.\" [1 mark]</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"Finance.\"</em><br/>\n      Too vague — this doesn''t state anything about the business.</p>\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"To pay for day-to-day expenses such as wages and stock.\"</em><br/>\n      Specific and directly answers the question.</p>\n      <p><strong>⚠️ Examiner Warning:</strong> If the question says \"other than expansion\", any answer linked to growth or opening new premises scores zero — even if it''s perfectly correct business knowledge. Always re-read the exact wording.</p>\n    ", "question": "What must you avoid when answering a question that says ''other than expansion''?", "options": ["Giving an answer that mentions research and development costs", "Giving any answer linked to growth or opening new premises", "Giving an answer that mentions replacing old machinery or equipment", "Giving an answer that mentions day-to-day running costs like wages"]}'::jsonb, '{"answer": 1, "explain": "The card warns that when a question excludes expansion, any growth-related answer scores zero — even if it is otherwise correct business knowledge — so re-read the exact wording."}'::jsonb),
('business:5-2-sources-of-finance:tips:0db32b21', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tips', 'mcq', 1, '{"readingTitle": "State One Disadvantage — 2 marks (1+1) — Two Disadvantages, One Each — Don''t Confuse Them", "reading": "\n      <p>Some questions ask you to state one disadvantage of <strong>two different sources of finance</strong> — one mark each. These are knowledge-only questions, so no application or analysis is needed.</p>\n      <p><strong>Example question:</strong> \"State one disadvantage to a business owner of using: (a) their own capital, (b) a bank loan.\" [2 marks]</p>\n      <p><strong>Formula:</strong> State the disadvantage clearly for each source. Keep it simple.</p>\n      <p><strong>✅ Owner''s capital (1 mark):</strong><br/>\n      <em>\"Using savings will leave the owner with less money for personal use / emergencies.\"</em></p>\n      <p><strong>✅ Bank loan (1 mark):</strong><br/>\n      <em>\"Interest must be paid on the loan, increasing the total cost for the business.\"</em></p>\n      <p><strong>⚠️ Examiner Warning:</strong> Students often write a disadvantage of the wrong source — e.g. writing about interest for owner''s capital. Always make sure your disadvantage logically matches the source it''s asking about.</p>\n    ", "question": "What is the most common mistake in a ''state one disadvantage of each'' question?", "options": ["Writing the disadvantage using bullet points instead of full sentences", "Writing a disadvantage that doesn''t logically match the source being asked about", "Failing to mention any specific source of finance at all in the answer", "Writing far more disadvantages than the actual number the question really asks for"]}'::jsonb, '{"answer": 1, "explain": "The card warns students often write a disadvantage of the wrong source — e.g. mentioning interest for owner''s capital — so the disadvantage must logically match the source asked about."}'::jsonb),
('business:5-2-sources-of-finance:tips:7a5f032e', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The U → APP → AN Chain: Three Steps, Zero Shortcuts", "reading": "\n      <p>For a 3-mark analyse question, you need to follow the <strong>Understanding → Application → Analysis</strong> chain. You will score ZERO for the analysis mark if you do not apply to the specific business in the case study.</p>\n      <p><strong>The 3-step formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U):</strong> State the benefit or drawback of this source of finance. What is it?</li>\n        <li><strong>Step 2 — Application (APP):</strong> Link it to the specific business in the case study. Use their name, figures, or context.</li>\n        <li><strong>Step 3 — Analysis (AN):</strong> Explain the financial or operational impact on the business. What does this mean for their costs, cash flow, profit, or growth?</li>\n      </ul>\n      <p><strong>Sentence starters:</strong><br/>\n      U: \"A share issue means the business can raise money without paying interest...\"<br/>\n      APP: \"For CFM, which has a negative closing balance of -£5,500...\"<br/>\n      AN: \"...this will reduce their financial costs, helping them improve their net profit margin.\"</p>\n      <p><strong>❌ Bad Answer (1 mark max):</strong><br/>\n      <em>\"A share issue is good because it raises money. This is good for the business.\"</em><br/>\n      No application to the case study, no real analysis.</p>\n      <p><strong>✅ Full-Mark Answer (3 marks):</strong><br/>\n      <em>\"A share issue raises finance without requiring repayment (U). This is useful for CFM as they are considering becoming a private limited company and need to fund a new café costing several thousand pounds (APP). By avoiding a bank loan, Martin and Anne will not have to pay interest, keeping their costs low and protecting their 25% net profit margin (AN).\"</em></p>\n      <p><strong>🚫 Examiner Warning — \"Knowledge Dumping\":</strong> Writing everything you know about share issues without referring to the specific business scores very few marks. The examiner is testing whether you can apply theory to context, not just recall theory.</p>\n    ", "question": "What score do you get for the analysis mark if you don''t apply to the case study business?", "options": ["Zero — the analysis mark requires application to the specific business", "One mark, regardless of whether or not you apply the answer", "Half marks, since basic understanding alone still counts for quite a lot", "Full marks, since analysis can always be entirely theoretical"]}'::jsonb, '{"answer": 0, "explain": "The card states you score zero for the analysis mark without applying to the case study business — the U to APP to AN chain requires application before analysis can be credited."}'::jsonb),
('business:5-2-sources-of-finance:tips:8f829016', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tips', 'mcq', 1, '{"readingTitle": "Recommend — 3 marks — You MUST Compare Both Options to Get Full Marks", "reading": "\n      <p>A 3-mark ''Recommend'' question asks you to choose between <strong>two specific sources of finance</strong> and justify your choice. This is the most commonly failed question type on this topic.</p>\n      <p><strong>The 3-mark formula:</strong></p>\n      <ul>\n        <li><strong>Mark 1 — Judgement:</strong> State your clear recommendation. \"CFM should use retained profit / a share issue.\"</li>\n        <li><strong>Mark 2 — Justification:</strong> Explain why your chosen option is BETTER THAN the other. You must cover BOTH methods.</li>\n        <li><strong>Mark 3 — Context:</strong> Embed a specific detail from the case study to support your comparison.</li>\n      </ul>\n      <p><strong>Sentence starter:</strong><br/>\n      \"I recommend [Option A] because... Unlike [Option B], this will... Given that the case study states [specific detail], this means...\"</p>\n      <p><strong>❌ Bad Answer (1 mark only):</strong><br/>\n      <em>\"CFM should use retained profit. It is free and they won''t have to pay it back.\"</em><br/>\n      This only discusses the chosen option — no comparison with a share issue, no context.</p>\n      <p><strong>✅ Full-Mark Answer:</strong><br/>\n      <em>\"CFM should use retained profit (JUDGEMENT). Unlike a share issue, retained profit does not require Martin and Anne to sell part of their business, so they keep full control (JUSTIFICATION). Since CFM has only been trading for two years and has a negative cash flow forecast (-£5,500 closing balance), bringing in outside shareholders could lead to pressure to prioritise profit over the partners'' goals (CONTEXT).\"</em></p>\n      <p><strong>⚠️ Examiner Warning:</strong> Over 50% of students fail to score more than 1 mark on this type of question. The most common mistake is repeating points from the previous two questions without making a clear comparison. The examiner wants new reasoning — not a summary of what you already said.</p>\n    ", "question": "According to this card, why do most students fail to score well on ''recommend'' questions?", "options": ["They forget to state any final judgement anywhere in their answer", "They recommend an option that isn''t actually mentioned anywhere in the case study", "They write far more detail than the three available marks actually require", "They repeat earlier points without making a clear comparison between the two options"]}'::jsonb, '{"answer": 3, "explain": "The card explains over 50% of students fail to score more than 1 mark by repeating earlier points instead of making a genuine new comparison between the two options."}'::jsonb),
('business:5-2-sources-of-finance:tips:7bf67d17', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'tips', 'mcq', 1, '{"readingTitle": "Evaluate — 7 marks — Argue Both Sides, Then Make a Justified Conclusion", "reading": "\n      <p>A 7-mark evaluate question uses Levels of Response marking. You need to demonstrate application, analysis AND evaluation — in that order.</p>\n      <p><strong>Structure your answer in 4 paragraphs:</strong></p>\n      <p><strong>Paragraph 1 — Understanding & Option A (K + U):</strong><br/>\n      Explain what source of finance A is and one reason it could be appropriate.<br/>\n      <em>\"Owner''s capital is money the owner uses from their own savings. For Martina, who has just over £5,000 in savings, this would mean no interest payments...\"</em></p>\n      <p><strong>Paragraph 2 — Analysis & Application of Option A (AN + APP):</strong><br/>\n      Develop the impact on the business using case study details.<br/>\n      <em>\"However, as the equipment costs £5,000 and Martina has just over £5,000 saved, using all her savings would leave her with almost nothing to fall back on in the first months of trading, when the clinic is unlikely to be fully booked...\"</em></p>\n      <p><strong>Paragraph 3 — Analysis & Application of Option B (AN + APP):</strong><br/>\n      Now consider the second option (e.g. bank loan) with its impact.<br/>\n      <em>\"A bank loan would allow Martina to keep her savings as a financial safety net. However, interest charges would increase her monthly fixed costs, putting pressure on MD Sports Clinic''s cash flow, especially in its early months...\"</em></p>\n      <p><strong>Paragraph 4 — Evaluation (3 points: Decision + Context + Impact/Reasoning):</strong><br/>\n      Make a justified conclusion that goes beyond simply repeating your analysis.<br/>\n      <em>\"Overall, I recommend the bank loan. This is because Martina''s savings are barely enough to cover the equipment cost — leaving her with no contingency fund is very risky for a new business. The interest cost is manageable if she secures a low rate, and her stable cash flow forecast suggests she can afford the repayments. Ultimately, it depends on the interest rate offered — if it is high, using savings becomes more attractive.\"</em></p>\n      <p><strong>\"It Depends On...\" Rule:</strong> A conclusion that simply says \"Option A is best\" without nuance scores few evaluation marks. Examiners reward answers that identify the key condition or factor the decision hinges on.</p>\n    ", "question": "What do examiners reward in the final evaluation paragraph, according to this card?", "options": ["Avoiding a final decision so that both options remain equally valid", "Identifying the key condition or factor that the final decision actually depends on", "Simply stating that one option is the best one without giving any further reasoning", "Repeating the two earlier analysis paragraphs in a slightly shorter form"]}'::jsonb, '{"answer": 1, "explain": "The card''s ''It Depends On...'' rule explains examiners reward identifying the key factor the decision hinges on, rather than a bare judgement or a repeat of earlier analysis."}'::jsonb),
('business:5-2-sources-of-finance:fib:87f5f327', 'business', 'business:5-2-sources-of-finance', '5.2 Sources of Finance', 'fib', 'fib', 2, '{"question": "An overdraft is a _____ source of finance that allows a business to spend more than it has in its _____.", "blankOptions": {"B1": ["medium-term", "short-term", "established", "loan"], "B2": ["instalments", "owners", "loan", "bank account"]}}'::jsonb, '{"blanks": {"B1": "short-term", "B2": "bank account"}}'::jsonb),
